;(function(){System.register([],function(exports,module){'use strict';return{execute:function(){(Drupal2=>{const odssDropdownSearchable={elements:{searchableDropdowns:[...document.querySelectorAll(".odss-dropdown[data-dropdown-searchable]")]},methods:{initialize:()=>{odssDropdownSearchable.methods.setupSearchListeners();},setupSearchListeners:()=>{odssDropdownSearchable.elements.searchableDropdowns.forEach(dropdown=>{const searchInput=dropdown.querySelector("[data-dropdown-search]");if(!searchInput){return;}searchInput.addEventListener("input",()=>{odssDropdownSearchable.methods.filterItems(searchInput);});});},filterItems:searchInput=>{const searchValue=searchInput.value.toLowerCase();const dropdown=searchInput.closest(".odss-dropdown");if(!dropdown){return;}const checkboxes=dropdown.querySelectorAll(".oui-checkbox");checkboxes.forEach(checkbox=>{const label=checkbox.querySelector(".oui-label__text");if(!label){return;}const labelText=label.textContent?.toLowerCase()||"";if(labelText.includes(searchValue)){checkbox.style.display="";}else{checkbox.style.display="none";}});}},events:{},attach:()=>odssDropdownSearchable.methods.initialize()};Drupal2.behaviors.odssDropdownSearchable=odssDropdownSearchable;})(Drupal);}};});})();
